    #[test]
    fn device_gpu_chat_skips_openvino() {
        let gpu = GpuCapabilities::new(false, true);
        let r = resolve_backend("gpu", "", ModelType::Chat, &gpu).unwrap();
        // OpenVINO not valid for chat, so falls back to CPU
